//! Validated identifier type.

/// A validated MLPL identifier.
///
/// Must start with an ASCII letter or underscore, followed by
/// ASCII letters, digits, or underscores. Never empty.
#[derive(Clone, Debug, PartialEq, Eq, Hash)]
pub struct Identifier(String);

impl Identifier {
    /// Create a new identifier from a string, validating it.
    ///
    /// Returns `None` if the string is not a valid identifier.
    pub fn new(s: &str) -> Option<Self> {
        if is_valid_ident(s) {
            Some(Self(s.to_owned()))
        } else {
            None
        }
    }

    /// Return the identifier as a string slice.
    #[must_use]
    pub fn as_str(&self) -> &str {
        &self.0
    }
}

impl std::fmt::Display for Identifier {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.write_str(&self.0)
    }
}

/// Check whether a string is a valid MLPL identifier.
///
/// Rules (from syntax-core-v1):
/// - Must not be empty
/// - First character: ASCII letter or underscore
/// - Subsequent characters: ASCII letters, digits, or underscores
fn is_valid_ident(s: &str) -> bool {
    let mut chars = s.chars();
    match chars.next() {
        Some(c) if c.is_ascii_alphabetic() || c == '_' => {}
        _ => return false,
    }
    chars.all(|c| c.is_ascii_alphanumeric() || c == '_')
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn valid_simple() {
        assert!(Identifier::new("x").is_some());
        assert!(Identifier::new("my_var").is_some());
        assert!(Identifier::new("result2").is_some());
    }

    #[test]
    fn valid_underscore_start() {
        assert!(Identifier::new("_temp").is_some());
        assert!(Identifier::new("_").is_some());
        assert!(Identifier::new("__double").is_some());
    }

    #[test]
    fn invalid_empty() {
        assert!(Identifier::new("").is_none());
    }

    #[test]
    fn invalid_starts_with_digit() {
        assert!(Identifier::new("2fast").is_none());
        assert!(Identifier::new("0x").is_none());
    }

    #[test]
    fn invalid_special_chars() {
        assert!(Identifier::new("my-var").is_none());
        assert!(Identifier::new("hello!").is_none());
        assert!(Identifier::new("a b").is_none());
        assert!(Identifier::new("x+y").is_none());
    }

    #[test]
    fn invalid_unicode() {
        assert!(Identifier::new("caf\u{00e9}").is_none());
    }

    #[test]
    fn as_str_roundtrip() {
        let id = Identifier::new("foo").unwrap();
        assert_eq!(id.as_str(), "foo");
    }

    #[test]
    fn display() {
        let id = Identifier::new("my_var").unwrap();
        assert_eq!(id.to_string(), "my_var");
    }

    #[test]
    fn equality() {
        let a = Identifier::new("x").unwrap();
        let b = Identifier::new("x").unwrap();
        let c = Identifier::new("y").unwrap();
        assert_eq!(a, b);
        assert_ne!(a, c);
    }

    #[test]
    fn clone() {
        let a = Identifier::new("x").unwrap();
        let b = a.clone();
        assert_eq!(a, b);
    }
}

